#include <stdio.h>
#include <stdlib.h>

int main() {
    int n1, b1;
    scanf("%d %d", &n1, &b1);
    int *d1 = malloc(n1 * sizeof(int));
    for (int i = 0; i < n1; i++) {
        scanf("%d", &d1[i]);
    }

    int n2, b2;
    scanf("%d %d", &n2, &b2);
    int *d2 = malloc(n2 * sizeof(int));
    for (int i = 0; i < n2; i++) {
        scanf("%d", &d2[i]);
    }

    long long answer1 = 0;
    long long power1 = 1;
    for (int i = n1 - 1; i >= 0; i--) {
        answer1 += d1[i] * power1;
        power1 *= b1;
    }

    long long answer2 = 0;
    long long power2 = 1;
    for (int i = n2 - 1; i >= 0; i--) {
        answer2 += d2[i] * power2;
        power2 *= b2;
    }

    if (answer1 < answer2) {
        printf("<\n");
    } else if (answer2 < answer1) {
        printf(">\n");
    } else {
        printf("=\n");
    }

    free(d1);
    free(d2);
    return 0;
}
